274 /// Return true if we do not know how to (mechanically) hoist or sink \p R out
275 /// of a loop region.
276 static bool cannotHoistOrSinkRecipe(const VPRecipeBase &R) {
277   // Assumes don't alias anything or throw; as long as they're guaranteed to
278   // execute, they're safe to hoist.
279   if (match(&R, m_Intrinsic<Intrinsic::assume>()))
280     return false;
281 
282   // TODO: Relax checks in the future, e.g. we could also hoist reads, if their
283   // memory location is not modified in the vector loop.
284   if (R.mayHaveSideEffects() || R.mayReadFromMemory() || R.isPhi())
285     return true;
286 
287   // Allocas cannot be hoisted.
288   auto *RepR = dyn_cast<VPReplicateRecipe>(&R);
289   return RepR && RepR->getOpcode() == Instruction::Alloca;
290 }
