292 static bool sinkScalarOperands(VPlan &Plan) {
293   auto Iter = vp_depth_first_deep(Plan.getEntry());
294   bool ScalarVFOnly = Plan.hasScalarVFOnly();
295   bool Changed = false;
296 
297   SetVector<std::pair<VPBasicBlock *, VPSingleDefRecipe *>> WorkList;
298   auto InsertIfValidSinkCandidate = [ScalarVFOnly, &WorkList](
299                                         VPBasicBlock *SinkTo, VPValue *Op) {
300     auto *Candidate =
301         dyn_cast_or_null<VPSingleDefRecipe>(Op->getDefiningRecipe());
302     if (!Candidate)
303       return;
304 
305     // We only know how to sink VPReplicateRecipes and VPScalarIVStepsRecipes
306     // for now.
307     if (!isa<VPReplicateRecipe, VPScalarIVStepsRecipe>(Candidate))
308       return;
309 
310     if (Candidate->getParent() == SinkTo || cannotHoistOrSinkRecipe(*Candidate))
311       return;
312 
313     if (auto *RepR = dyn_cast<VPReplicateRecipe>(Candidate))
314       if (!ScalarVFOnly && RepR->isSingleScalar())
315         return;
316 
317     WorkList.insert({SinkTo, Candidate});
318   };
319 
320   // First, collect the operands of all recipes in replicate blocks as seeds for
321   // sinking.
322   for (VPRegionBlock *VPR : VPBlockUtils::blocksOnly<VPRegionBlock>(Iter)) {
323     VPBasicBlock *EntryVPBB = VPR->getEntryBasicBlock();
324     if (!VPR->isReplicator() || EntryVPBB->getSuccessors().size() != 2)
325       continue;
326     VPBasicBlock *VPBB = cast<VPBasicBlock>(EntryVPBB->getSuccessors().front());
327     if (VPBB->getSingleSuccessor() != VPR->getExitingBasicBlock())
328       continue;
329     for (auto &Recipe : *VPBB)
330       for (VPValue *Op : Recipe.operands())
331         InsertIfValidSinkCandidate(VPBB, Op);
332   }
333 
334   // Try to sink each replicate or scalar IV steps recipe in the worklist.
335   for (unsigned I = 0; I != WorkList.size(); ++I) {
336     VPBasicBlock *SinkTo;
337     VPSingleDefRecipe *SinkCandidate;
338     std::tie(SinkTo, SinkCandidate) = WorkList[I];
339 
340     // All recipe users of SinkCandidate must be in the same block SinkTo or all
341     // users outside of SinkTo must only use the first lane of SinkCandidate. In
342     // the latter case, we need to duplicate SinkCandidate.
343     auto UsersOutsideSinkTo =
344         make_filter_range(SinkCandidate->users(), [SinkTo](VPUser *U) {
345           return cast<VPRecipeBase>(U)->getParent() != SinkTo;
346         });
347     if (any_of(UsersOutsideSinkTo, [SinkCandidate](VPUser *U) {
348           return !U->usesFirstLaneOnly(SinkCandidate);
349         }))
350       continue;
351     bool NeedsDuplicating = !UsersOutsideSinkTo.empty();
352 
353     if (NeedsDuplicating) {
354       if (ScalarVFOnly)
355         continue;
356       VPSingleDefRecipe *Clone;
357       if (auto *SinkCandidateRepR =
358               dyn_cast<VPReplicateRecipe>(SinkCandidate)) {
359         // TODO: Handle converting to uniform recipes as separate transform,
360         // then cloning should be sufficient here.
361         Instruction *I = SinkCandidate->getUnderlyingInstr();
