4678 template <unsigned Opcode>
4679 static SmallVector<SmallVector<VPReplicateRecipe *, 4>>
4680 collectComplementaryPredicatedMemOps(VPlan &Plan,
4681                                      PredicatedScalarEvolution &PSE,
4682                                      const Loop *L) {
4683   static_assert(Opcode == Instruction::Load || Opcode == Instruction::Store,
4684                 "Only Load and Store opcodes supported");
4685   constexpr bool IsLoad = (Opcode == Instruction::Load);
4686   VPTypeAnalysis TypeInfo(Plan);
4687 
4688   // For each address, collect operations with the same or complementary masks.
4689   SmallVector<SmallVector<VPReplicateRecipe *, 4>> AllGroups;
4690   auto GetLoadStoreValueType = [&](VPReplicateRecipe *Recipe) {
4691     return TypeInfo.inferScalarType(IsLoad ? Recipe : Recipe->getOperand(0));
4692   };
4693   auto Groups = collectGroupedReplicateMemOps<Opcode>(
4694       Plan, PSE, L,
4695       [](VPReplicateRecipe *RepR) { return RepR->isPredicated(); });
4696   for (auto Recipes : Groups) {
4697     if (Recipes.size() < 2)
4698       continue;
4699 
4700     // Collect groups with the same or complementary masks.
4701     for (VPReplicateRecipe *&RecipeI : Recipes) {
4702       if (!RecipeI)
4703         continue;
4704 
4705       VPValue *MaskI = RecipeI->getMask();
4706       Type *TypeI = GetLoadStoreValueType(RecipeI);
4707       SmallVector<VPReplicateRecipe *, 4> Group;
4708       Group.push_back(RecipeI);
4709       RecipeI = nullptr;
4710 
4711       // Find all operations with the same or complementary masks.
4712       bool HasComplementaryMask = false;
4713       for (VPReplicateRecipe *&RecipeJ : Recipes) {
4714         if (!RecipeJ)
4715           continue;
4716 
4717         VPValue *MaskJ = RecipeJ->getMask();
4718         Type *TypeJ = GetLoadStoreValueType(RecipeJ);
4719         if (TypeI == TypeJ) {
4720           // Check if any operation in the group has a complementary mask with
4721           // another, that is M1 == NOT(M2) or M2 == NOT(M1).
4722           HasComplementaryMask |= match(MaskI, m_Not(m_Specific(MaskJ))) ||
4723                                   match(MaskJ, m_Not(m_Specific(MaskI)));
4724           Group.push_back(RecipeJ);
4725           RecipeJ = nullptr;
4726         }
4727       }
4728 
4729       if (HasComplementaryMask) {
4730         assert(Group.size() >= 2 && "must have at least 2 entries");
4731         AllGroups.push_back(std::move(Group));
4732       }
4733     }
4734   }
4735 
4736   return AllGroups;
4737 }
