394 /// If \p R is a triangle region, return the 'then' block of the triangle.
395 static VPBasicBlock *getPredicatedThenBlock(VPRegionBlock *R) {
396   auto *EntryBB = cast<VPBasicBlock>(R->getEntry());
397   if (EntryBB->getNumSuccessors() != 2)
398     return nullptr;
399 
400   auto *Succ0 = dyn_cast<VPBasicBlock>(EntryBB->getSuccessors()[0]);
401   auto *Succ1 = dyn_cast<VPBasicBlock>(EntryBB->getSuccessors()[1]);
402   if (!Succ0 || !Succ1)
403     return nullptr;
404 
405   if (Succ0->getNumSuccessors() + Succ1->getNumSuccessors() != 1)
406     return nullptr;
407   if (Succ0->getSingleSuccessor() == Succ1)
408     return Succ0;
409   if (Succ1->getSingleSuccessor() == Succ0)
410     return Succ1;
411   return nullptr;
