4792 static bool
4793 canSinkStoreWithNoAliasCheck(ArrayRef<VPReplicateRecipe *> StoresToSink,
4794                              PredicatedScalarEvolution &PSE, const Loop &L,
4795                              VPTypeAnalysis &TypeInfo) {
4796   auto StoreLoc = vputils::getMemoryLocation(*StoresToSink.front());
4797   if (!StoreLoc || !StoreLoc->AATags.Scope)
4798     return false;
4799 
4800   // When sinking a group of stores, all members of the group alias each other.
4801   // Skip them during the alias checks.
4802   SmallPtrSet<VPRecipeBase *, 4> StoresToSinkSet(StoresToSink.begin(),
4803                                                  StoresToSink.end());
4804 
4805   VPBasicBlock *FirstBB = StoresToSink.front()->getParent();
4806   VPBasicBlock *LastBB = StoresToSink.back()->getParent();
4807   SinkStoreInfo SinkInfo(StoresToSinkSet, *StoresToSink[0], PSE, L, TypeInfo);
4808   return canHoistOrSinkWithNoAliasCheck(*StoreLoc, FirstBB, LastBB, SinkInfo);
