4811 void VPlanTransforms::sinkPredicatedStores(VPlan &Plan,
4812                                            PredicatedScalarEvolution &PSE,
4813                                            const Loop *L) {
4814   auto Groups =
4815       collectComplementaryPredicatedMemOps<Instruction::Store>(Plan, PSE, L);
4816   if (Groups.empty())
4817     return;
4818 
4819   VPTypeAnalysis TypeInfo(Plan);
4820 
4821   for (auto &Group : Groups) {
4822     if (!canSinkStoreWithNoAliasCheck(Group, PSE, *L, TypeInfo))
4823       continue;
4824 
4825     // Use the last (most dominated) store's location for the unconditional
4826     // store.
4827     VPReplicateRecipe *LastStore = Group.back();
4828     VPBasicBlock *InsertBB = LastStore->getParent();
4829 
4830     // Collect common alias metadata from all stores in the group.
4831     VPIRMetadata CommonMetadata = getCommonMetadata(Group);
4832 
4833     // Build select chain for stored values.
4834     VPValue *SelectedValue = Group[0]->getOperand(0);
4835     VPBuilder Builder(InsertBB, LastStore->getIterator());
4836 
4837     bool IsSingleScalar = Group[0]->isSingleScalar();
4838     for (unsigned I = 1; I < Group.size(); ++I) {
4839       assert(IsSingleScalar == Group[I]->isSingleScalar() &&
4840              "all members in group must agree on IsSingleScalar");
4841       VPValue *Mask = Group[I]->getMask();
4842       VPValue *Value = Group[I]->getOperand(0);
4843       SelectedValue = Builder.createSelect(Mask, Value, SelectedValue,
4844                                            Group[I]->getDebugLoc());
4845     }
4846 
4847     // Find the store with minimum alignment to use.
4848     auto *StoreWithMinAlign = findRecipeWithMinAlign<StoreInst>(Group);
4849 
4850     // Create unconditional store with selected value and common metadata.
4851     auto *UnpredicatedStore = new VPReplicateRecipe(
4852         StoreWithMinAlign->getUnderlyingInstr(),
4853         {SelectedValue, LastStore->getOperand(1)}, IsSingleScalar,
4854         /*Mask=*/nullptr, *LastStore, CommonMetadata);
4855     UnpredicatedStore->insertBefore(*InsertBB, LastStore->getIterator());
4856 
4857     // Remove all predicated stores from the group.
4858     for (VPReplicateRecipe *Store : Group)
4859       Store->eraseFromParent();
4860   }
